Then('Location modal will closed', async function () {
  // Wait up to 8s for the location/postcode modal to disappear. Scope tightly to the
  // postcode modal markers — generic [role="dialog"] would match cookie banners etc.
  const _closed = await this.page.waitForFunction(() => {
    const sels = [
      '#locaion-modal-input',
      '.hyu-postcode-modal',
      '.js-hyu-postcode-modal--btn-set-dealer',
      '.tingle-modal--visible'
    ];
    for (const sel of sels) {
      const el = document.querySelector(sel);
      if (!el) continue;
      const r = el.getBoundingClientRect();
      const cs = getComputedStyle(el);
      if (r.width > 0 && r.height > 0 && cs.display !== 'none' && cs.visibility !== 'hidden') return false;
    }
    return true;
  }, { timeout: 8000 }).then(() => true).catch(() => false);
  console.log(`📋 Location modal closed: ${_closed}`);
  assert.ok(_closed, 'Location modal will closed');
});

